<?php class Program{private $c;function __construct($d){$this->c=$d;}function all(){ $r=$this->c->query('SELECT * FROM programs ORDER BY created_at DESC');$a=[];while($x=$r->fetch_assoc())$a[]=$x;return $a;}function create($d){foreach($d as $k=>$v)$d[$k]=$this->c->real_escape_string($v);return $this->c->query("INSERT INTO programs(program_title,project_cost,leader,assistant_leader,members,start_date,end_date,special_order_no) VALUES('{$d['program_title']}','{$d['project_cost']}','{$d['leader']}','{$d['assistant_leader']}','{$d['members']}','{$d['start_date']}','{$d['end_date']}','{$d['special_order_no']}')");}} ?>